sys_script_include.script:
function BusinessProcessGetExample()
{
	var businessprocess =
	{
		name: 'Simple Task',
		id: 'simple_task',
		description: 'The Simple Task process manages work requested by the Requesters and which is done by Fulfillers. Once Fulfillers report work to be completed, Requesters can either confirm and close the task or request the continuation of the work.',
		input: 'Details on the task to be performed.',
		output: 'The results demanded by the requestor and documented evidence of task completion.',
		initial_state: 'new',
		_roles:
		[
			{
				id: 'requester',
				name: 'Requester',
				description: 'A user that can open simple tasks and request their delivery'
			},
			{
				id: 'fulfiller',
				name: 'Fulfiller',
				description: 'A user that works on simple tasks'
			},
			{
				id: 'manager',
				name: 'Manager',
				description: 'A user that oversees the execution of the process and can perform all state transitions'
			}			
		],
		_states: 
		[
			{
				id: 'new',
				name: 'New',
				description: 'The initial state of a simple task. Requesters create a new tasks in the "New" state.',
				_transitions: [ 'request' ]
			},
			{
				id: 'requested',
				name: 'Requested',
				description: 'The task is now requested and waits to be worked on by a Fulfiller.',
				_transitions: ['start_work','cancel']
			},
			{
				id: 'work_in_progress',
				name: 'Work in Progress',
				description: 'The task is now being worked on by a Fulfiller.',
				_transitions: ['complete', 'cancel']
			},
			{
				id: 'complete',
				name: 'Work is completed',
				description: 'The task is considered completed by the Fulfiller.',
				_transitions: ['work_in_progress', 'close', 'cancel']
			},
			{
				id: 'closed',
				name: 'Closed',
				description: 'The task is confirmed completed and closed by the Requester.',
				_transitions: []
			},
			{
				id: 'cancelled',
				name: 'Cancelled',
				description: 'The task is cancelled and will no longer be worked on.',
				_transitions: []
			}		
		],
		_transitions:
		[
			{
				id: 'request',
				label: 'Request',
				target_state: 'requested',
				_roles: [ 'requester', 'manager' ]
			},
			{
				id: 'start_work',
				label: 'Start work',
				target_state: 'work_in_progress',
				_roles: [ 'fulfiller', 'manager' ]
			},
			{
				id: 'complete',
				label: 'Work Completed',
				target_state: 'complete',
				_roles: [ 'fulfiller', 'manager' ]
			},		
			{
				id: 'close',
				label: 'Close',
				target_state: 'closed',
				_roles: [ 'requester', 'manager' ]
			},						
			{
				id: 'cancel',
				label: 'Cancel',
				target_state: 'cancelled',
				_roles: [ 'requester', 'manager' ]
			}
		]
	};
	return businessprocess;
}
